namespace sv_181745508aac4c9fa4aab83ca9e2d1b5.Client.Services;

public interface IShipmentService
{
    Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

public record ShipmentDetails(
    string TrackingNumber,
    string Status,
    string Location,
    DateTimeOffset EstimatedDelivery,
    IReadOnlyList<StatusUpdate> StatusUpdates);

public record StatusUpdate(
    string Description,
    string Location,
    DateTimeOffset Timestamp);

using System.Net.Http.Json;

namespace sv_181745508aac4c9fa4aab83ca9e2d1b5.Client.Services;

public class ClientShipmentService(HttpClient httpClient) : IShipmentService
{
    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var result = await httpClient.GetFromJsonAsync<ShipmentDetails>(
            $"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);
        return result ?? throw new InvalidOperationException("Shipment not found.");
    }
}

using sv_181745508aac4c9fa4aab83ca9e2d1b5.Client.Services;

namespace sv_181745508aac4c9fa4aab83ca9e2d1b5.Services;

public class ServerShipmentService : IShipmentService
{
    private static readonly Dictionary<string, ShipmentDetails> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["PKG-001"] = new ShipmentDetails(
            "PKG-001",
            "In Transit",
            "Memphis, TN",
            DateTimeOffset.UtcNow.AddDays(2),
            [
                new StatusUpdate("Package picked up", "New York, NY", DateTimeOffset.UtcNow.AddDays(-3)),
                new StatusUpdate("Arrived at sorting facility", "Newark, NJ", DateTimeOffset.UtcNow.AddDays(-2)),
                new StatusUpdate("In transit to destination", "Memphis, TN", DateTimeOffset.UtcNow.AddDays(-1)),
            ]),
        ["PKG-002"] = new ShipmentDetails(
            "PKG-002",
            "Delivered",
            "San Francisco, CA",
            DateTimeOffset.UtcNow.AddDays(-1),
            [
                new StatusUpdate("Package picked up", "Seattle, WA", DateTimeOffset.UtcNow.AddDays(-5)),
                new StatusUpdate("Arrived at sorting facility", "Portland, OR", DateTimeOffset.UtcNow.AddDays(-4)),
                new StatusUpdate("Out for delivery", "San Francisco, CA", DateTimeOffset.UtcNow.AddDays(-1)),
                new StatusUpdate("Delivered", "San Francisco, CA", DateTimeOffset.UtcNow.AddDays(-1).AddHours(3)),
            ]),
        ["PKG-003"] = new ShipmentDetails(
            "PKG-003",
            "Processing",
            "Chicago, IL",
            DateTimeOffset.UtcNow.AddDays(5),
            [
                new StatusUpdate("Label created", "Chicago, IL", DateTimeOffset.UtcNow.AddHours(-6)),
                new StatusUpdate("Awaiting carrier pickup", "Chicago, IL", DateTimeOffset.UtcNow.AddHours(-1)),
            ]),
    };

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        // Simulate slow backend
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"No shipment found for tracking number '{trackingNumber}'.");
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_181745508aac4c9fa4aab83ca9e2d1b5.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="alert alert-info" role="status">
        <p><strong>Loading shipment details for @TrackingNumber...</strong></p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-danger mt-2" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is not null)
{
    <h2>Shipment @_shipment.TrackingNumber</h2>
    <dl class="row">
        <dt class="col-sm-3">Status</dt>
        <dd class="col-sm-9">@_shipment.Status</dd>

        <dt class="col-sm-3">Location</dt>
        <dd class="col-sm-9">@_shipment.Location</dd>

        <dt class="col-sm-3">Estimated Delivery</dt>
        <dd class="col-sm-9">@_shipment.EstimatedDelivery.ToString("f")</dd>
    </dl>

    <h4>Status History</h4>
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Time</th>
                <th>Description</th>
                <th>Location</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var update in _shipment.StatusUpdates)
            {
                <tr>
                    <td>@update.Timestamp.ToString("g")</td>
                    <td>@update.Description</td>
                    <td>@update.Location</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = default!;

    private ShipmentDetails? _shipment;
    private bool _loading;
    private string? _errorMessage;

    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _loading = true;
        _errorMessage = null;
        _shipment = null;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or component disposed; do nothing.
            return;
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException || ex.CancellationToken != ct)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex) when (ex is not OperationCanceledException)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
            StateHasChanged();
        }
    }

    private async Task RetryAsync()
    {
        await LoadShipmentAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

